scwin.mgntInfoClsCd = "";
scwin.privAdmin     = $c.gus.cfIsNull( $c.data.getMemInfo("privAdmin") ) ? '': $c.data.getMemInfo("privAdmin");

scwin.G_acctDeptCd = $c.gus.cfIsNull( $c.data.getMemInfo("acctDeptCd") ) ? '': $c.data.getMemInfo("acctDeptCd");
scwin.G_acctDeptNm = $c.gus.cfIsNull( $c.data.getMemInfo("acctDeptNm") ) ? '': $c.data.getMemInfo("acctDeptNm");
scwin.G_empNo = $c.gus.cfIsNull( $c.data.getMemInfo("empNo") ) ? '': $c.data.getMemInfo("empNo");
scwin.G_empNm = $c.gus.cfIsNull( $c.data.getMemInfo("userNm") ) ? '': $c.data.getMemInfo("userNm");

scwin.vLoginCoCd    = $c.gus.cfIsNull( $c.data.getMemInfo("coCd") ) ? '': $c.data.getMemInfo("coCd");   // 소속 자회사
scwin.vLoginCoClsCd = $c.gus.cfIsNull( $c.data.getMemInfo("coClsCd") ) ? '': $c.data.getMemInfo("coClsCd"); //회계_회사구분('CO035' : 0:동부 EXPRESS)
scwin.vUserHomeClsCd = $c.gus.cfIsNull( $c.data.getMemInfo("userHomeClsCd") ) ? '': $c.data.getMemInfo("userHomeClsCd");    // 사용자소속구분코드 


scwin.isSubCompany = false;
scwin.txtCoClsCd = "";
scwin.today = $c.date.getServerDateTime("yyyyMMdd");

scwin.onpageload = function() {

};

scwin.onUdcCompleted = function() {
    //f_Header();
    ed_FromDate.setValue( scwin.today );
    scwin.f_GetVersion();
    scwin.f_setCompanyInfo();

    $c.gus.cfDisableObjects([ed_crcCd]);
    $c.gus.cfDisableObjects([ed_crcCdNm]);
    $c.gus.cfDisableObjects([ed_abroadYn]);
    $c.gus.cfDisableObjects([ed_adptExchRt]);
    $c.gus.cfDisableObjects([ed_planAdptExchRt]);
}

scwin.ondataload = function () {

}

scwin.btn_reset_onclick = function (e) {
    $c.gus.cfInitObjects();
};

scwin.btn_search_onclick = function (e) {
    scwin.f_Retrieve();
};

// 자회사 회계 시스템 추가에 따른 설정 
scwin.f_setCompanyInfo = async function() {
    // 사용자 구분이 자회사('SA')가 아닌 경우, 소속회사를  '동부 EXPRESS'로  Default set
    if( scwin.vUserHomeClsCd != ACConstants.SUBSIDIARY_USER_HOME_CLS_CD)  {
        scwin.vLoginCoCd = ACConstants.CO_CD_DONGBU;
        scwin.vLoginCoClsCd =  ACConstants.CO_CLS_CD_DONGBU;
    }

    ed_coCd.setValue( scwin.vLoginCoCd );
    await scwin.f_PopUpCompanyInfoAsync('T'); 

    debugger;

    if(scwin.txtCoClsCd > ACConstants.CO_CLS_CD_DONGBU)  {  	// 자회사 회계 시스템 
        scwin.isSubCompany = true;
    }else{
        scwin.isSubCompany = false;
    }

    //회사코드 수정 권한
    if(scwin.G_acctDeptCd=="00004" || scwin.G_acctDeptCd=="00009") {  //경영전략팀
        $c.gus.cfEnableObjects([ed_coCd,ed_coNm,btn_company ]);
    }else {
        if(scwin.G_acctDeptCd=="00062"){  //인천지사 로엑스 담당이 자회사 실적 업로드하여 해당 부서만 변경가능하도록 수정
            ed_coCd.setValue("011");
            ed_coNm.setValue("");
            scwin.f_PopUpCompanyInfo('T'); 
        }
        $c.gus.cfDisableObjects([ed_coCd,ed_coNm,btn_company ]);
    }
}

scwin.udc_coCd_cb = function(rtnList) {
    // SET
    if(rtnList != null ) {
        if (rtnList[0] == "N/A") return;
        ed_coCd.setValue( rtnList[0] );  	// 코드
        ed_coNm.setValue( rtnList[5] ); 	// 회사명 
        scwin.txtCoClsCd  = rtnList[1];	// 회사구분 
    }else{
        ed_coCd.setValue("");
        ed_coNm.setValue("");
        scwin.txtCoClsCd = "";
    }

    ed_mgntInfoClsCd.setValue("");
    ed_mgntInfoClsCdNm.setValue("");
    ed_crcCd.setValue("");
    ed_crcCdNm.setValue("");
    ed_adptExchRt.setValue("");
    ed_planAdptExchRt.setValue("");
}


// 회사 입력 팝업 
scwin.f_PopUpCompanyInfoAsync = async function(pWinCloseTF) {
    udc_coCd.setSelectId("retrieveDongbuGroupCompanyInfo");
    await udc_coCd.cfCommonPopUpAsync(scwin.udc_coCd_cb
                            ,ed_coCd.getValue(), ed_coNm.getValue()
                            ,pWinCloseTF,null,null,null,null
                            ,null,null,null,"T",null);
}


// 회사 입력 팝업 
scwin.f_PopUpCompanyInfo = function(pWinCloseTF) {
    udc_coCd.setSelectId("retrieveDongbuGroupCompanyInfo");
    udc_coCd.cfCommonPopUp(scwin.udc_coCd_cb
                            ,ed_coCd.getValue(), ed_coNm.getValue()
                            ,pWinCloseTF,null,null,null,null
                            ,null,null,null,"T",null);
}

scwin.sbm_search_cb = function(e) {
    ed_totalRows.setValue( ds_info.getRowCount() );

    //cfHideDSWaitMsg(gr_info);
	if( ds_info.getRowCount() == 0 ){
		$c.gus.cfAlertMsg(MSG_CM_ERR_003);
	}

	// 산술식 계산 호출
	scwin.f_Cal(); 

	if(ds_info.getCellData(0, "confirmPlanRsltYn")== 1){
		$c.gus.cfDisableObjects([ed_planAdptExchRt]);
		gr_info.setColumnReadOnly("thisMmPlanAmt", true);
        gr_info.setColumnReadOnly("thisMmPlanRcrcAmt", true);
	} else {
		$c.gus.cfEnableObjects([ed_planAdptExchRt]);
		gr_info.setColumnReadOnly("thisMmPlanAmt", false);
        gr_info.setColumnReadOnly("thisMmPlanRcrcAmt", false);
	}
}


//-------------------------------------------------------------------------
// 조회
//-------------------------------------------------------------------------
scwin.f_Retrieve = async function() {
    let ret;

    if(ed_abroadYn.getValue() ==1){
        // 필수 입력 확인
        ret = await $c.gus.cfValidate([ed_FromDate,ed_mgntInfoClsCd]);
        if (!ret){
            return;
        }
        var e = await $c.sbm.execute(sbm_search);
        scwin.sbm_search_cb(e);
    }

    // 필수 입력 확인
    ret = await $c.gus.cfValidate([ed_FromDate,ed_mgntInfoClsCd]);
    if (!ret){
        return;
    }

    debugger;
    // 그리드의 환율을 필드로
    ed_adptExchRt.setValue( ds_info.getCellData(0,"adptExchRt") );
    ed_planAdptExchRt.setValue( ds_info.getCellData(0,"planAdptExchRt") );
    debugger;

    //해외여부가 no 일경우 환율 clear
    if(ed_abroadYn.getValue() == 2 ){
        ed_adptExchRt.setValue("");
        ed_planAdptExchRt.setValue("");
    }

    // 입력구분코드
    scwin.mgntInfoClsCd = dma_search.get("mgntInfoClsCd");

    var res = await  $c.sbm.execute(sbm_search);
    scwin.sbm_search_cb(res);
    console.log(res);

    debugger;

}


