    ret = await $c.win.confirm(MSG_CM_CRM_001);
    if(ret){
        dma_search.set("confirmRsltYn", 1);
        //ds_search.UseChangeInfo="false";			
        //tr_confirmRsltUpdate.Post();
        //tr_search.Post();
        console.log(dma_search.getJSON());
        $c.sbm.execute(sbm_confirmRsltUpdate);
    }
}

//-------------------------------------------------------------------------
// 실적금액확정취소
//-------------------------------------------------------------------------
scwin.f_cancel_rslts_close = async function() {	

    let ret;
    // 필수 입력 확인
    ret = await $c.gus.cfValidate([ed_FromDate,ed_mgntInfoClsCd]);
    if (!ret){
        return;
