    //ds_planMagam.Reset(); 
    //sbm_planMagam.action = "/cm.zz.RetrieveCommonPopupCMD.do?sysCd=CommonEBC&queryId=dinymicQueryTest" + "&param1=" + param1 + "&param2=" + param2 + "&param3=" + param3 + "&param4=" + param4;
    $c.sbm.execute(sbm_planMagam);
